/* 1. Function Declaration (Prototype) */
return_type function_name(parameter_type1 param1, parameter_type2 param2);

/* 2. Function Definition */
[storage_class] return_type function_name(parameter_type1 param1, parameter_type2 param2) {
    // Function body (local statements)
    return expression; // Optional if return_type is void
}

/* 3. Function Call */
return_type variable = function_name(actual_arg1, actual_arg2);

/* 4. Storage Class Specifiers */
auto int local_var = 10;
register int quick_counter = 0;
static int persistent_state = 5;
extern int shared_global_var;

codeExample1.code:
#include <stdio.h>

// Function declarations (prototypes)
void testCallByValue(int dynamicParam);
int getPersistentID(void);

int main(void) {
    int originalVar = 100;

    printf("[MAIN] Original value before function call: %d\n", originalVar);

    // Call by Value invocation: copy of originalVar is passed
    testCallByValue(originalVar);

    printf("[MAIN] Original value after function call: %d (Unchanged!)\n\n", originalVar);

    // Call a function that uses a static local variable
    printf("[MAIN] Unique ID Call 1: %d\n", getPersistentID());
    printf("[MAIN] Unique ID Call 2: %d\n", getPersistentID());
    printf("[MAIN] Unique ID Call 3: %d\n", getPersistentID());

    return 0;
}

// Function Definitions
void testCallByValue(int dynamicParam) {
    printf("[FUNC] Received local copy: %d\n", dynamicParam);
    dynamicParam += 50; // Modify only the local parameter variable
    printf("[FUNC] Modified copy inside function: %d\n", dynamicParam);
}

int getPersistentID(void) {
    // Static variable is initialized only ONCE when the program starts
    // Its value persists in memory for the lifetime of the program execution
    static int generatedID = 1000;
    generatedID++;
    return generatedID;
}

codeExample2.code:
#include <stdio.h>

// Recursive function to compute factorial of a number
unsigned long long calculateFactorial(int n) {
    // Print statement to trace Stack Frame activation
    printf("Entering Stack Frame: calculateFactorial(n = %d) at address: %p\n", n, (void*)&n);

    // 1. Base Case: Prevent infinite recursion
    if (n <= 1) {
        printf("  -> Base case reached! Returning 1 from Frame (n = %d)\n", n);
        return 1;
    }

    // 2. Recursive Case
    unsigned long long subResult = calculateFactorial(n - 1);
    unsigned long long finalResult = n * subResult;

    printf("Exiting Stack Frame: calculateFactorial(n = %d) with return value: %llu\n", n, finalResult);
    return finalResult;
}

int main(void) {
    int targetNumber = 4;
    printf("[MAIN] Initiating execution of calculateFactorial(%d)\n\n", targetNumber);

    unsigned long long result = calculateFactorial(targetNumber);

    printf("\n[MAIN] Final computed result: %llu\n", result);
    return 0;
}

