Here is the code:

#include <stdio.h>

// Prototype
int isPrime(int val);

int isPrime(int val) {
    if (val <= 1) return 0; // Check boundary cases
    if (val == 2) return 1; // 2 is prime
    if (val % 2 == 0) return 0; // Eliminate even numbers

    // Test odd factors up to the square root of val
    for (int i = 3; i * i <= val; i += 2) {
        if (val % i == 0) {
            return 0; // Found a factor, not prime
        }
    }
    return 1; // Prime
}

Here is the code:

#include <stdio.h>

unsigned long long fibonacci(int n) {
    if (n < 0) return 0; // Handle invalid bounds
    if (n == 0) return 0; // Base Case 1
    if (n == 1) return 1; // Base Case 2
    return fibonacci(n - 1) + fibonacci(n - 2);
}

